import { useParams, Link } from 'react-router-dom';
import { useState, useEffect } from 'react';
import Header from '../../components/feature/Header';
import Footer from '../../components/feature/Footer';
import geoData from '../../data/geo-service-data.json';
import { supabase } from '../../lib/supabase';

export default function ServiceAreaPage() {
    const { area } = useParams<{ area: string }>();
    const [content, setContent] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    const areaData = geoData.areas.find(a => a.slug === area);

    useEffect(() => {
        async function fetchArea() {
            setLoading(true);

            // 1. Try Supabase
            try {
                const { data, error } = await supabase
                    .from('areas')
                    .select('*')
                    .eq('slug', area || '')
                    .single();

                if (data && !error) {
                    setContent(data);
                } else {
                    // 2. Fallback to JSON
                    const fallback = (geoData.area_content as any)[area || ''];
                    setContent(fallback);
                }
            } catch (err) {
                const fallback = (geoData.area_content as any)[area || ''];
                setContent(fallback);
            }
            setLoading(false);
        }

        if (area) {
            fetchArea();
        }
    }, [area]);

    if (loading) {
        return <div className="min-h-screen flex items-center justify-center">Loading...</div>;
    }

    if (!areaData || !content) {
        return (
            <div className="min-h-screen bg-white">
                <Header />
                <div className="py-24 text-center">
                    <h1 className="text-4xl font-bold mb-4">Area Not Found</h1>
                    <p className="text-gray-600 mb-8">Sorry, we don't currently list {area} as a primary service area.</p>
                    <Link to="/" className="text-blue-600 font-semibold hover:underline">Return to Homepage</Link>
                </div>
                <Footer />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-white">
            <Header />

            {/* Hero Section */}
            <section
                className="relative py-24 bg-cover bg-center"
                style={{
                    backgroundImage: `linear-gradient(rgba(0, 0, 0, 0.6), rgba(0, 0, 0, 0.6)), url('https://readdy.ai/api/search-image?query=${encodeURIComponent(`${areaData.name} BC landscape, community landmarks, suburban area`)}&width=1920&height=800&seq=area-hero-1&orientation=landscape')`
                }}
            >
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center text-white">
                        <h1 className="text-5xl lg:text-6xl font-bold mb-6">
                            {content.title}
                        </h1>
                        <p className="text-xl mb-8 max-w-3xl mx-auto text-gray-200">
                            {content.description}
                        </p>
                        <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
                            <button
                                onClick={() => (document.querySelector('#vapi-widget-floating-button') as HTMLElement)?.click()}
                                className="bg-blue-600 text-white px-10 py-5 rounded-xl text-xl font-bold hover:bg-blue-700 transition-all shadow-xl hover:scale-105 active:scale-95 whitespace-nowrap cursor-pointer flex items-center justify-center gap-2"
                            >
                                <i className="ri-user-voice-fill"></i>
                                Talk to Our AI HVAC Assistant
                            </button>
                            <button
                                onClick={() => window.REACT_APP_NAVIGATE?.('/contact')}
                                className="bg-white/10 backdrop-blur-md border border-white/20 text-white px-10 py-5 rounded-xl text-xl font-bold hover:bg-white/20 transition-all hover:scale-105 active:scale-95 whitespace-nowrap cursor-pointer"
                            >
                                Request Online Quote
                            </button>
                        </div>
                    </div>
                </div>
            </section>

            {/* Landmarks / Local SEO Section */}
            <section className="py-12 bg-gray-50 border-b">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                    <p className="text-gray-600 italic">
                        Proudly serving the {areaData.name} community, including areas near {content.landmark_mention}.
                    </p>
                </div>
            </section>

            {/* Services in this Area */}
            <section className="py-16 bg-white">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center mb-12">
                        <h2 className="text-3xl font-bold text-gray-900 mb-4">Available Services in {areaData.name}</h2>
                        <p className="text-lg text-gray-600 max-w-2xl mx-auto">
                            Our full range of HVAC and plumbing services are available to homes and businesses in {areaData.name}.
                        </p>
                    </div>

                    <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
                        {geoData.services.map(service => (
                            <Link
                                key={service.slug}
                                to={`/services/${service.slug}/${areaData.slug}`}
                                className="group border border-gray-100 rounded-xl p-6 bg-gray-50 hover:bg-white hover:shadow-xl transition-all"
                            >
                                <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center mb-4 group-hover:bg-blue-600 transition-colors">
                                    <i className="ri-tools-line text-blue-600 group-hover:text-white text-xl"></i>
                                </div>
                                <h3 className="text-xl font-bold mb-2 group-hover:text-blue-600">{service.name}</h3>
                                <p className="text-gray-600 text-sm">Expert {service.name.toLowerCase()} for your {areaData.name} property.</p>
                                <div className="mt-4 flex items-center text-blue-600 font-semibold text-sm">
                                    View {service.name} Details
                                    <i className="ri-arrow-right-line ml-2"></i>
                                </div>
                            </Link>
                        ))}
                    </div>
                </div>
            </section>

            {/* Local Importance Section */}
            <section className="py-16 bg-blue-600 text-white">
                <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                    <h2 className="text-3xl font-bold mb-6">Proudly Serving the {areaData.name} Community</h2>
                    <p className="text-xl leading-relaxed text-blue-50/90">
                        {content.landmark_mention} We understand the unique HVAC needs of {areaData.name} residents,
                        from proper air filtration during the dry months to high-efficiency heating when the winter chill sets in.
                    </p>
                </div>
            </section>

            <Footer />
        </div>
    );
}
